import heapq
from collections import defaultdict

def medianSlidingWindow(nums, k):
    lo, hi = [], []  # max-heap (negated), min-heap
    lazy = defaultdict(int)

    def add(num):
        if not lo or num <= -lo[0]:
            heapq.heappush(lo, -num)
        else:
            heapq.heappush(hi, num)
        rebalance()

    def remove(num):
        lazy[num] += 1
        if lo and num <= -lo[0]:
            rebalance()
        else:
            rebalance()

    def rebalance():
        while lo and lazy[-lo[0]] > 0:
            lazy[-lo[0]] -= 1
            heapq.heappop(lo)
        while hi and lazy[hi[0]] > 0:
            lazy[hi[0]] -= 1
            heapq.heappop(hi)
        while len(lo) < len(hi): heapq.heappush(lo, -heapq.heappop(hi))
        while len(lo) > len(hi) + 1: heapq.heappush(hi, -heapq.heappop(lo))

    def get_median():
        return -lo[0] * 1.0 if k % 2 == 1 else (-lo[0] + hi[0]) / 2.0

    for num in nums[:k]: add(num)
    result = [get_median()]
    for i in range(k, len(nums)):
        add(nums[i])
        remove(nums[i - k])
        rebalance()
        result.append(get_median())
    return result

